const period = $('Check if weekly digest is due').first().json;
const stats = $('Query week stats').first().json;
const dailyBreakdown = $('Query daily breakdown').all().map(i => i.json);
const failures = $('Query open failures').all().map(i => i.json);

const fmtDate = d => new Date(d + 'T00:00:00+05:30').toLocaleDateString('en-IN', { weekday: 'short', day: 'numeric', month: 'short' });
const weekLabel = `${fmtDate(period.period_start)} – ${fmtDate(period.period_end)}`;
const fmtINR = n => Number(n).toLocaleString('en-IN', { style: 'currency', currency: 'INR' });

const dayRows = dailyBreakdown.length === 0
  ? '<tr><td colspan="4" style="color:#999">No transactions this week</td></tr>'
  : dailyBreakdown.map(d => {
      const dayName = new Date(d.day + 'T00:00:00+05:30').toLocaleDateString('en-IN', { weekday: 'short', day: 'numeric', month: 'short' });
      return `<tr><td>${dayName}</td><td>${d.transactions}</td><td>${fmtINR(d.spent)}</td><td>${fmtINR(d.received)}</td></tr>`;
    }).join('');

let failureRows = failures.length === 0
  ? '<tr><td colspan="4" style="color:green">None — all clear</td></tr>'
  : failures.map(f =>
      `<tr><td>${f.id}</td><td>${f.stage}</td><td>${f.subject || '—'}</td><td>${f.error_message?.substring(0, 80) || '—'}</td></tr>`
    ).join('');

const html = `
<html><body style="font-family: sans-serif; color: #222; max-width: 700px; margin: auto">
<h2>Finance pipeline — weekly digest</h2>
<p style="color: #666">${weekLabel}</p>

<h3>Week summary</h3>
<table border="1" cellpadding="6" cellspacing="0" style="border-collapse:collapse; width:100%">
  <tr style="background:#f0f0f0"><th>Metric</th><th>Value</th></tr>
  <tr><td>Emails ingested</td><td>${stats.raw_ingested}</td></tr>
  <tr><td>Transactions written</td><td>${stats.written_to_ebk}</td></tr>
  <tr><td>Deduplicated (dropped)</td><td>${stats.deduplicated}</td></tr>
  <tr><td>GroqCloud fallback calls</td><td>${stats.groq_calls}</td></tr>
  <tr><td>Open failures</td><td style="color:${stats.open_failures > 0 ? 'red' : 'green'}">${stats.open_failures}</td></tr>
  <tr><td>Week spend</td><td>${fmtINR(stats.week_spend)}</td></tr>
  <tr><td>Month-to-date spend</td><td>${fmtINR(stats.month_spend)}</td></tr>
</table>

<h3>Daily breakdown</h3>
<table border="1" cellpadding="6" cellspacing="0" style="border-collapse:collapse; width:100%">
  <tr style="background:#f0f0f0"><th>Day</th><th>Transactions</th><th>Spent</th><th>Received</th></tr>
  ${dayRows}
</table>

<h3>Open failures</h3>
<table border="1" cellpadding="6" cellspacing="0" style="border-collapse:collapse; width:100%">
  <tr style="background:#f0f0f0"><th>ID</th><th>Stage</th><th>Email subject</th><th>Error</th></tr>
  ${failureRows}
</table>

<p style="font-size:12px;color:#999">To mark a failure resolved: <code>UPDATE failed_events SET resolved=TRUE WHERE id=&lt;id&gt;;</code><br>
To promote a Groq pattern to regex: see RUNBOOK.md</p>
</body></html>
`;

return [{ json: { subject: `Finance weekly digest — ${weekLabel}`, html, period_end: period.period_end } }];
